export interface ZambianAct {
  /** Short name for display */
  name: string;
  /** Full legal citation */
  citation: string;
  /** Chapter number in Laws of Zambia (if cap-numbered) */
  chapter?: string;
  /** Act number and year (for newer acts) */
  actNumber?: string;
  /** Relevance to contracts */
  relevance: string;
  /** Key provisions */
  keyProvisions: string[];
  /** Contract types this law applies to */
  applicableContractTypes: string[];
}

