// ---------------------------------------------------------------------------
// Helper: Get legislation applicable to a contract type
// ---------------------------------------------------------------------------

export function getLegislationForContractType(contractType: string): ZambianAct[] {
  return ZAMBIAN_LEGISLATION.filter(
    (act) =>
      act.applicableContractTypes.includes("all") ||
      act.applicableContractTypes.includes(contractType),
  );
}

// ---------------------------------------------------------------------------
// Helper: Get a formatted legal citation string for documents
// ---------------------------------------------------------------------------

export function getGoverningLawText(): string {
  return "This Agreement shall be governed by and construed in accordance with the Laws of the Republic of Zambia, including but not limited to the Constitution of Zambia (Amendment) Act, 2016, and all subsidiary legislation applicable thereto.";
}

export function getDisputeResolutionText(includeArbitration: boolean = false): string {
  if (includeArbitration) {
    return (
      "Any dispute, difference, or question arising out of or in connection with this Agreement shall first be resolved through good-faith negotiation between the parties. " +
      "If negotiation fails within thirty (30) days, the dispute shall be referred to mediation administered by a mutually agreed mediator. " +
      "If mediation is unsuccessful within a further thirty (30) days, the dispute shall be submitted to binding arbitration in accordance with the Arbitration Act, Chapter 40 of the Laws of Zambia. " +
      "The arbitration shall be conducted in Lusaka by a sole arbitrator appointed by agreement of the parties, or failing agreement within fourteen (14) days, by the President of the Law Association of Zambia. " +
      "The arbitral award shall be final and binding on both parties."
    );
  }
  return (
    "Any dispute arising from or in connection with this Agreement shall first be resolved through good-faith negotiation between the parties. " +
    "If negotiation fails within thirty (30) days, the dispute shall be referred to mediation. " +
    "If mediation is unsuccessful, the dispute shall be submitted to the exclusive jurisdiction of the courts of Lusaka, Republic of Zambia."
  );
}

